SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- Table structure for article
-- ----------------------------
DROP TABLE IF EXISTS `article`;
CREATE TABLE `article`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '文章ID',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '文章标题',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '文章内容(Markdown格式)',
  `html_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '文章内容(HTML格式)',
  `summary` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '文章摘要',
  `cover_image` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '封面图片',
  `category_id` bigint NULL DEFAULT NULL COMMENT '分类ID',
  `user_id` bigint NOT NULL COMMENT '作者ID',
  `view_count` int NULL DEFAULT 0 COMMENT '浏览量',
  `like_count` int NULL DEFAULT 0 COMMENT '点赞数',
  `comment_count` int NULL DEFAULT 0 COMMENT '评论数',
  `status` tinyint NULL DEFAULT 1 COMMENT '状态(0:草稿,1:已发布,2:已删除)',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_top` tinyint NULL DEFAULT 0 COMMENT '是否置顶(0:否,1:是)',
  `is_recommend` tinyint NULL DEFAULT 0 COMMENT '是否推荐(0:否,1:是)',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category_id`(`category_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 100 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '文章表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of article
-- ----------------------------
INSERT INTO `article` VALUES (1, '个人博客系统开发文档', '\n1. 项目概述\n本项目是一个基于SpringBoot+Vue3的个人博客系统，采用前后端分离架构，实现博客内容的发布、管理、展示等功能。系统分为前台展示和后台管理两大部分，为用户提供良好的阅读体验和博主提供便捷的内容管理能力。\n1.1 技术栈\n前端：Vue3 + Element Plus + Axios + Vue Router + Pinia\n后端：Spring Boot + MyBatis-Plus + JWT\n数据库：MySQL\n开发工具：IDEA、VS Code\n版本控制：Git\n1.2 系统角色\n游客：未登录用户，可浏览博客内容、搜索文章、查看评论\n注册用户：可进行评论、点赞、收藏等操作\n博主/管理员：拥有内容发布、编辑、删除等管理权限\n2. 功能模块划分\n2.1 前台展示模块\n2.1.1 首页模块\n博客基本信息展示\n最新文章列表\n热门文章推荐\n文章分类导航\n标签云展示\n2.1.2 文章模块\n文章详情页\n文章评论区\n文章点赞功能\n文章收藏功能\n相关文章推荐\n2.1.3 分类与标签模块\n分类文章列表\n标签文章列表\n文章归档\n2.1.4 搜索模块\n全文搜索功能\n搜索结果展示\n2.1.5 用户中心\n用户资料查看与修改\n用户评论管理\n收藏文章管理\n2.2 后台管理模块\n2.2.1 用户管理\n用户信息管理\n用户权限控制\n2.2.2 文章管理\n文章发布（支持Markdown编辑器）\n文章编辑\n文章删除\n文章状态管理（草稿、已发布、已删除）\n2.2.3 分类管理\n分类新增\n分类编辑\n分类删除\n2.2.4 标签管理\n标签新增\n标签编辑\n标签删除\n2.2.5 评论管理\n评论审核\n评论回复\n评论删除\n2.2.6 系统设置\n博客基本信息设置\n首页轮播图设置\n友情链接管理\n关于我页面管理\n3. 数据库设计\n3.1 数据库表结构\n3.1.1 用户表(user)\n字段名类型约束说明idbigint主键、自增用户IDusernamevarchar(50)非空、唯一用户名passwordvarchar(100)非空密码(加密存储)emailvarchar(100)非空、唯一邮箱phonevarchar(20)手机号role_codevarchar(50)角色code(ADMIN/USER)namevarchar(50)姓名sexvarchar(255)性别avatarvarchar(200)头像statustinyint默认值1状态(0:禁用,1:正常)create_timedatetime默认当前时间创建时间update_timedatetime默认当前时间更新时间\n3.1.2 文章表(article)\n字段名类型约束说明idbigint主键、自增文章IDtitlevarchar(100)非空文章标题contentlongtext非空文章内容(Markdown格式)html_contentlongtext非空文章内容(HTML格式)summaryvarchar(255)文章摘要cover_imagevarchar(200)封面图片category_idbigint分类IDuser_idbigint非空作者IDview_countint默认值0浏览量like_countint默认值0点赞数comment_countint默认值0评论数statustinyint默认值1状态(0:草稿,1:已发布,2:已删除)create_timedatetime默认当前时间创建时间update_timedatetime默认当前时间更新时间is_toptinyint默认值0是否置顶(0:否,1:是)is_recommendtinyint默认值0是否推荐(0:否,1:是)\n3.1.3 文章分类表(category)\n字段名类型约束说明idbigint主键、自增分类IDnamevarchar(50)非空分类名称descriptionvarchar(200)分类描述parent_idbigint默认值0父分类ID(0表示顶级分类)order_numint默认值0排序号create_timedatetime默认当前时间创建时间update_timedatetime默认当前时间更新时间\n3.1.4 标签表(tag)\n字段名类型约束说明idbigint主键、自增标签IDnamevarchar(50)非空标签名称colorvarchar(20)标签颜色create_timedatetime默认当前时间创建时间update_timedatetime默认当前时间更新时间\n3.1.5 文章标签关联表(article_tag)\n字段名类型约束说明idbigint主键、自增关联IDarticle_idbigint非空文章IDtag_idbigint非空标签ID\n3.1.6 评论表(comment)\n字段名类型约束说明idbigint主键、自增评论IDcontentvarchar(500)非空评论内容article_idbigint非空文章IDuser_idbigint非空评论用户IDparent_idbigint默认值0父评论ID(0表示顶级评论)to_user_idbigint默认值0回复用户ID(0表示不是回复)statustinyint默认值1状态(0:待审核,1:已通过,2:已拒绝)create_timedatetime默认当前时间创建时间update_timedatetime默认当前时间更新时间\n3.1.7 用户收藏表(user_collect)\n字段名类型约束说明idbigint主键、自增收藏IDuser_idbigint非空用户IDarticle_idbigint非空文章IDcreate_timedatetime默认当前时间创建时间\n3.1.8 用户点赞表(user_like)\n字段名类型约束说明idbigint主键、自增点赞IDuser_idbigint非空用户IDarticle_idbigint非空文章IDcreate_timedatetime默认当前时间创建时间\n3.1.9 博客设置表(blog_config)\n字段名类型约束说明idbigint主键、自增设置IDconfig_keyvarchar(50)非空配置键config_valuetext非空配置值create_timedatetime默认当前时间创建时间update_timedatetime默认当前时间更新时间\n3.1.10 友情链接表(friend_link)\n字段名类型约束说明idbigint主键、自增链接IDnamevarchar(50)非空链接名称urlvarchar(200)非空链接地址logovarchar(200)链接logodescriptionvarchar(200)链接描述order_numint默认值0排序号statustinyint默认值1状态(0:隐藏,1:显示)create_timedatetime默认当前时间创建时间update_timedatetime默认当前时间更新时间\n3.2 表关系说明\n用户与文章：一对多关系，一个用户可以发布多篇文章\n文章与分类：多对一关系，多篇文章可以属于同一分类\n文章与标签：多对多关系，通过article_tag表关联\n用户与评论：一对多关系，一个用户可以发表多条评论\n文章与评论：一对多关系，一篇文章可以有多条评论\n评论与评论：自关联，实现评论回复功能\n4. 接口设计\n4.1 前台接口\n4.1.1 文章相关接口\n获取首页文章列表：GET /api/articles\n获取文章详情：GET /api/articles/{id}\n获取推荐文章：GET /api/articles/recommend\n获取最热文章：GET /api/articles/hot\n文章搜索：GET /api/articles/search?keyword={keyword}\n获取分类文章：GET /api/categories/{id}/articles\n获取标签文章：GET /api/tags/{id}/articles\n文章点赞：POST /api/articles/{id}/like\n文章收藏：POST /api/articles/{id}/collect\n4.1.2 分类标签接口\n获取所有分类：GET /api/categories\n获取所有标签：GET /api/tags\n4.1.3 评论相关接口\n获取文章评论：GET /api/articles/{id}/comments\n发表评论：POST /api/comments\n回复评论：POST /api/comments/{id}/reply\n4.1.4 用户相关接口\n用户注册：POST /api/register\n用户登录：POST /api/login\n获取用户信息：GET /api/users/{id}\n修改用户信息：PUT /api/users/{id}\n获取用户收藏列表：GET /api/users/{id}/collections\n获取用户评论列表：GET /api/users/{id}/comments\n4.2 后台接口\n4.2.1 文章管理接口\n创建文章：POST /api/admin/articles\n更新文章：PUT /api/admin/articles/{id}\n删除文章：DELETE /api/admin/articles/{id}\n获取文章列表：GET /api/admin/articles\n修改文章状态：PUT /api/admin/articles/{id}/status\n4.2.2 分类管理接口\n创建分类：POST /api/admin/categories\n更新分类：PUT /api/admin/categories/{id}\n删除分类：DELETE /api/admin/categories/{id}\n获取分类列表：GET /api/admin/categories\n4.2.3 标签管理接口\n创建标签：POST /api/admin/tags\n更新标签：PUT /api/admin/tags/{id}\n删除标签：DELETE /api/admin/tags/{id}\n获取标签列表：GET /api/admin/tags\n4.2.4 评论管理接口\n获取评论列表：GET /api/admin/comments\n审核评论：PUT /api/admin/comments/{id}/status\n删除评论：DELETE /api/admin/comments/{id}\n4.2.5 用户管理接口\n获取用户列表：GET /api/admin/users\n更新用户状态：PUT /api/admin/users/{id}/status\n重置用户密码：PUT /api/admin/users/{id}/password\n4.2.6 系统设置接口\n获取博客配置：GET /api/admin/config\n更新博客配置：PUT /api/admin/config\n获取友链列表：GET /api/admin/friendLinks\n创建友链：POST /api/admin/friendLinks\n更新友链：PUT /api/admin/friendLinks/{id}\n删除友链：DELETE /api/admin/friendLinks/{id}\n上传图片：POST /api/admin/upload/image\n5. 开发计划\n5.1 第一阶段 - 基础功能开发\n搭建项目框架，完成基础配置\n完成用户模块开发（注册、登录、信息管理）\n完成文章基础功能（CRUD操作）\n完成分类和标签基础功能\n5.2 第二阶段 - 核心功能开发\n完成文章详情页展示\n实现评论功能\n实现文章点赞、收藏功能\n开发文章搜索功能\n5.3 第三阶段 - 扩展功能开发\n完善首页展示和推荐算法\n实现文章统计和数据分析\n开发博客设置和个性化功能\n实现友情链接管理\n5.4 第四阶段 - 优化和测试\n性能优化（缓存、索引等）\nUI/UX优化\n安全性测试与加固\n全面功能测试与bug修复\n6. 项目部署\n6.1 开发环境\nJDK 17+\nNode.js 18+\nMySQL 8.0+\nMaven 3.8+\n6.2 生产环境\n服务器：Linux (Ubuntu/CentOS)\nWeb服务器：Nginx\n应用服务器：SpringBoot内置Tomcat\n数据库：MySQL 8.0+\n缓存：Redis (可选)\n6.3 部署步骤\n前端项目打包：npm run build\n后端项目打包：mvn clean package\n配置Nginx反向代理\n配置MySQL数据库\n启动后端服务\n配置域名和HTTPS (可选)\n7. 项目维护与更新计划\n7.1 定期维护\n安全漏洞修复\n依赖库更新\n性能监控与优化\n7.2 功能更新计划\n增加社交媒体分享功能\n集成第三方登录\n开发移动端适配\n增加数据统计和分析功能\n集成富文本编辑器选项\n', '<p><br></p><h2 style=\"text-align: start;\">1. 项目概述</h2><p style=\"text-align: start;\">本项目是一个基于SpringBoot+Vue3的个人博客系统，采用前后端分离架构，实现博客内容的发布、管理、展示等功能。系统分为前台展示和后台管理两大部分，为用户提供良好的阅读体验和博主提供便捷的内容管理能力。</p><h3 style=\"text-align: start;\">1.1 技术栈</h3><ul><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>前端</strong></span>：Vue3 + Element Plus + Axios + Vue Router + Pinia</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>后端</strong></span>：Spring Boot + MyBatis-Plus + JWT</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>数据库</strong></span>：MySQL</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>开发工具</strong></span>：IDEA、VS Code</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>版本控制</strong></span>：Git</li></ul><h3 style=\"text-align: start;\">1.2 系统角色</h3><ul><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>游客</strong></span>：未登录用户，可浏览博客内容、搜索文章、查看评论</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>注册用户</strong></span>：可进行评论、点赞、收藏等操作</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>博主/管理员</strong></span>：拥有内容发布、编辑、删除等管理权限</li></ul><h2 style=\"text-align: start;\">2. 功能模块划分</h2><h3 style=\"text-align: start;\">2.1 前台展示模块</h3><h4 style=\"text-align: start;\">2.1.1 首页模块</h4><ul><li style=\"text-align: start;\">博客基本信息展示</li><li style=\"text-align: start;\">最新文章列表</li><li style=\"text-align: start;\">热门文章推荐</li><li style=\"text-align: start;\">文章分类导航</li><li style=\"text-align: start;\">标签云展示</li></ul><h4 style=\"text-align: start;\">2.1.2 文章模块</h4><ul><li style=\"text-align: start;\">文章详情页</li><li style=\"text-align: start;\">文章评论区</li><li style=\"text-align: start;\">文章点赞功能</li><li style=\"text-align: start;\">文章收藏功能</li><li style=\"text-align: start;\">相关文章推荐</li></ul><h4 style=\"text-align: start;\">2.1.3 分类与标签模块</h4><ul><li style=\"text-align: start;\">分类文章列表</li><li style=\"text-align: start;\">标签文章列表</li><li style=\"text-align: start;\">文章归档</li></ul><h4 style=\"text-align: start;\">2.1.4 搜索模块</h4><ul><li style=\"text-align: start;\">全文搜索功能</li><li style=\"text-align: start;\">搜索结果展示</li></ul><h4 style=\"text-align: start;\">2.1.5 用户中心</h4><ul><li style=\"text-align: start;\">用户资料查看与修改</li><li style=\"text-align: start;\">用户评论管理</li><li style=\"text-align: start;\">收藏文章管理</li></ul><h3 style=\"text-align: start;\">2.2 后台管理模块</h3><h4 style=\"text-align: start;\">2.2.1 用户管理</h4><ul><li style=\"text-align: start;\">用户信息管理</li><li style=\"text-align: start;\">用户权限控制</li></ul><h4 style=\"text-align: start;\">2.2.2 文章管理</h4><ul><li style=\"text-align: start;\">文章发布（支持Markdown编辑器）</li><li style=\"text-align: start;\">文章编辑</li><li style=\"text-align: start;\">文章删除</li><li style=\"text-align: start;\">文章状态管理（草稿、已发布、已删除）</li></ul><h4 style=\"text-align: start;\">2.2.3 分类管理</h4><ul><li style=\"text-align: start;\">分类新增</li><li style=\"text-align: start;\">分类编辑</li><li style=\"text-align: start;\">分类删除</li></ul><h4 style=\"text-align: start;\">2.2.4 标签管理</h4><ul><li style=\"text-align: start;\">标签新增</li><li style=\"text-align: start;\">标签编辑</li><li style=\"text-align: start;\">标签删除</li></ul><h4 style=\"text-align: start;\">2.2.5 评论管理</h4><ul><li style=\"text-align: start;\">评论审核</li><li style=\"text-align: start;\">评论回复</li><li style=\"text-align: start;\">评论删除</li></ul><h4 style=\"text-align: start;\">2.2.6 系统设置</h4><ul><li style=\"text-align: start;\">博客基本信息设置</li><li style=\"text-align: start;\">首页轮播图设置</li><li style=\"text-align: start;\">友情链接管理</li><li style=\"text-align: start;\">关于我页面管理</li></ul><h2 style=\"text-align: start;\">3. 数据库设计</h2><h3 style=\"text-align: start;\">3.1 数据库表结构</h3><h4 style=\"text-align: start;\">3.1.1 用户表(user)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">用户ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">username</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(50)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空、唯一</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">用户名</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">password</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(100)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">密码(加密存储)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">email</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(100)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空、唯一</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">邮箱</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">phone</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(20)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">手机号</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">role_code</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(50)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">角色code(ADMIN/USER)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">name</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(50)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">姓名</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">sex</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(255)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">性别</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">avatar</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(200)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">头像</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">status</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">tinyint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值1</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">状态(0:禁用,1:正常)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">create_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">创建时间</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">update_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">更新时间</td></tr></tbody></table><h4 style=\"text-align: start;\">3.1.2 文章表(article)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">文章ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">title</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(100)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">文章标题</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">content</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">longtext</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">文章内容(Markdown格式)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">html_content</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">longtext</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">文章内容(HTML格式)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">summary</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(255)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">文章摘要</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">cover_image</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(200)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">封面图片</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">category_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">分类ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">user_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">作者ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">view_count</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">int</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">浏览量</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">like_count</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">int</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">点赞数</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">comment_count</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">int</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">评论数</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">status</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">tinyint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值1</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">状态(0:草稿,1:已发布,2:已删除)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">create_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">创建时间</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">update_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">更新时间</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">is_top</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">tinyint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">是否置顶(0:否,1:是)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">is_recommend</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">tinyint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">是否推荐(0:否,1:是)</td></tr></tbody></table><h4 style=\"text-align: start;\">3.1.3 文章分类表(category)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">分类ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">name</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(50)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">分类名称</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">description</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(200)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">分类描述</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">parent_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">父分类ID(0表示顶级分类)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">order_num</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">int</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">排序号</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">create_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">创建时间</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">update_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">更新时间</td></tr></tbody></table><h4 style=\"text-align: start;\">3.1.4 标签表(tag)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">标签ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">name</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(50)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">标签名称</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">color</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(20)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">标签颜色</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">create_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">创建时间</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">update_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">更新时间</td></tr></tbody></table><h4 style=\"text-align: start;\">3.1.5 文章标签关联表(article_tag)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">关联ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">article_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">文章ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">tag_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">标签ID</td></tr></tbody></table><h4 style=\"text-align: start;\">3.1.6 评论表(comment)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">评论ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">content</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(500)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">评论内容</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">article_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">文章ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">user_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">评论用户ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">parent_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">父评论ID(0表示顶级评论)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">to_user_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">回复用户ID(0表示不是回复)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">status</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">tinyint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值1</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">状态(0:待审核,1:已通过,2:已拒绝)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">create_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">创建时间</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">update_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">更新时间</td></tr></tbody></table><h4 style=\"text-align: start;\">3.1.7 用户收藏表(user_collect)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">收藏ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">user_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">用户ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">article_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">文章ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">create_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">创建时间</td></tr></tbody></table><h4 style=\"text-align: start;\">3.1.8 用户点赞表(user_like)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">点赞ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">user_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">用户ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">article_id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">文章ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">create_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">创建时间</td></tr></tbody></table><h4 style=\"text-align: start;\">3.1.9 博客设置表(blog_config)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">设置ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">config_key</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(50)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">配置键</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">config_value</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">text</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">配置值</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">create_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">创建时间</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">update_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">更新时间</td></tr></tbody></table><h4 style=\"text-align: start;\">3.1.10 友情链接表(friend_link)</h4><table style=\"width: auto; text-align: start;\"><tbody><tr><th colspan=\"1\" rowspan=\"1\" width=\"auto\">字段名</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">类型</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">约束</th><th colspan=\"1\" rowspan=\"1\" width=\"auto\">说明</th></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">id</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">bigint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">主键、自增</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">链接ID</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">name</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(50)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">链接名称</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">url</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(200)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">非空</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">链接地址</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">logo</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(200)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">链接logo</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">description</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">varchar(200)</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\"></td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">链接描述</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">order_num</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">int</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值0</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">排序号</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">status</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">tinyint</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认值1</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">状态(0:隐藏,1:显示)</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">create_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">创建时间</td></tr><tr><td colspan=\"1\" rowspan=\"1\" width=\"auto\">update_time</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">datetime</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">默认当前时间</td><td colspan=\"1\" rowspan=\"1\" width=\"auto\">更新时间</td></tr></tbody></table><h3 style=\"text-align: start;\">3.2 表关系说明</h3><ol><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>用户与文章</strong></span>：一对多关系，一个用户可以发布多篇文章</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>文章与分类</strong></span>：多对一关系，多篇文章可以属于同一分类</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>文章与标签</strong></span>：多对多关系，通过article_tag表关联</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>用户与评论</strong></span>：一对多关系，一个用户可以发表多条评论</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>文章与评论</strong></span>：一对多关系，一篇文章可以有多条评论</li><li style=\"text-align: start;\"><span style=\"color: rgb(0, 0, 0);\"><strong>评论与评论</strong></span>：自关联，实现评论回复功能</li></ol><h2 style=\"text-align: start;\">4. 接口设计</h2><h3 style=\"text-align: start;\">4.1 前台接口</h3><h4 style=\"text-align: start;\">4.1.1 文章相关接口</h4><ul><li style=\"text-align: start;\">获取首页文章列表：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/articles</code></span></li><li style=\"text-align: start;\">获取文章详情：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/articles/{id}</code></span></li><li style=\"text-align: start;\">获取推荐文章：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/articles/recommend</code></span></li><li style=\"text-align: start;\">获取最热文章：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/articles/hot</code></span></li><li style=\"text-align: start;\">文章搜索：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/articles/search?keyword={keyword}</code></span></li><li style=\"text-align: start;\">获取分类文章：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/categories/{id}/articles</code></span></li><li style=\"text-align: start;\">获取标签文章：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/tags/{id}/articles</code></span></li><li style=\"text-align: start;\">文章点赞：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/articles/{id}/like</code></span></li><li style=\"text-align: start;\">文章收藏：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/articles/{id}/collect</code></span></li></ul><h4 style=\"text-align: start;\">4.1.2 分类标签接口</h4><ul><li style=\"text-align: start;\">获取所有分类：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/categories</code></span></li><li style=\"text-align: start;\">获取所有标签：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/tags</code></span></li></ul><h4 style=\"text-align: start;\">4.1.3 评论相关接口</h4><ul><li style=\"text-align: start;\">获取文章评论：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/articles/{id}/comments</code></span></li><li style=\"text-align: start;\">发表评论：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/comments</code></span></li><li style=\"text-align: start;\">回复评论：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/comments/{id}/reply</code></span></li></ul><h4 style=\"text-align: start;\">4.1.4 用户相关接口</h4><ul><li style=\"text-align: start;\">用户注册：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/register</code></span></li><li style=\"text-align: start;\">用户登录：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/login</code></span></li><li style=\"text-align: start;\">获取用户信息：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/users/{id}</code></span></li><li style=\"text-align: start;\">修改用户信息：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/users/{id}</code></span></li><li style=\"text-align: start;\">获取用户收藏列表：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/users/{id}/collections</code></span></li><li style=\"text-align: start;\">获取用户评论列表：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/users/{id}/comments</code></span></li></ul><h3 style=\"text-align: start;\">4.2 后台接口</h3><h4 style=\"text-align: start;\">4.2.1 文章管理接口</h4><ul><li style=\"text-align: start;\">创建文章：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/admin/articles</code></span></li><li style=\"text-align: start;\">更新文章：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/admin/articles/{id}</code></span></li><li style=\"text-align: start;\">删除文章：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>DELETE /api/admin/articles/{id}</code></span></li><li style=\"text-align: start;\">获取文章列表：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/admin/articles</code></span></li><li style=\"text-align: start;\">修改文章状态：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/admin/articles/{id}/status</code></span></li></ul><h4 style=\"text-align: start;\">4.2.2 分类管理接口</h4><ul><li style=\"text-align: start;\">创建分类：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/admin/categories</code></span></li><li style=\"text-align: start;\">更新分类：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/admin/categories/{id}</code></span></li><li style=\"text-align: start;\">删除分类：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>DELETE /api/admin/categories/{id}</code></span></li><li style=\"text-align: start;\">获取分类列表：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/admin/categories</code></span></li></ul><h4 style=\"text-align: start;\">4.2.3 标签管理接口</h4><ul><li style=\"text-align: start;\">创建标签：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/admin/tags</code></span></li><li style=\"text-align: start;\">更新标签：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/admin/tags/{id}</code></span></li><li style=\"text-align: start;\">删除标签：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>DELETE /api/admin/tags/{id}</code></span></li><li style=\"text-align: start;\">获取标签列表：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/admin/tags</code></span></li></ul><h4 style=\"text-align: start;\">4.2.4 评论管理接口</h4><ul><li style=\"text-align: start;\">获取评论列表：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/admin/comments</code></span></li><li style=\"text-align: start;\">审核评论：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/admin/comments/{id}/status</code></span></li><li style=\"text-align: start;\">删除评论：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>DELETE /api/admin/comments/{id}</code></span></li></ul><h4 style=\"text-align: start;\">4.2.5 用户管理接口</h4><ul><li style=\"text-align: start;\">获取用户列表：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/admin/users</code></span></li><li style=\"text-align: start;\">更新用户状态：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/admin/users/{id}/status</code></span></li><li style=\"text-align: start;\">重置用户密码：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/admin/users/{id}/password</code></span></li></ul><h4 style=\"text-align: start;\">4.2.6 系统设置接口</h4><ul><li style=\"text-align: start;\">获取博客配置：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/admin/config</code></span></li><li style=\"text-align: start;\">更新博客配置：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/admin/config</code></span></li><li style=\"text-align: start;\">获取友链列表：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>GET /api/admin/friendLinks</code></span></li><li style=\"text-align: start;\">创建友链：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/admin/friendLinks</code></span></li><li style=\"text-align: start;\">更新友链：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>PUT /api/admin/friendLinks/{id}</code></span></li><li style=\"text-align: start;\">删除友链：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>DELETE /api/admin/friendLinks/{id}</code></span></li><li style=\"text-align: start;\">上传图片：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>POST /api/admin/upload/image</code></span></li></ul><h2 style=\"text-align: start;\">5. 开发计划</h2><h3 style=\"text-align: start;\">5.1 第一阶段 - 基础功能开发</h3><ol><li style=\"text-align: start;\">搭建项目框架，完成基础配置</li><li style=\"text-align: start;\">完成用户模块开发（注册、登录、信息管理）</li><li style=\"text-align: start;\">完成文章基础功能（CRUD操作）</li><li style=\"text-align: start;\">完成分类和标签基础功能</li></ol><h3 style=\"text-align: start;\">5.2 第二阶段 - 核心功能开发</h3><ol><li style=\"text-align: start;\">完成文章详情页展示</li><li style=\"text-align: start;\">实现评论功能</li><li style=\"text-align: start;\">实现文章点赞、收藏功能</li><li style=\"text-align: start;\">开发文章搜索功能</li></ol><h3 style=\"text-align: start;\">5.3 第三阶段 - 扩展功能开发</h3><ol><li style=\"text-align: start;\">完善首页展示和推荐算法</li><li style=\"text-align: start;\">实现文章统计和数据分析</li><li style=\"text-align: start;\">开发博客设置和个性化功能</li><li style=\"text-align: start;\">实现友情链接管理</li></ol><h3 style=\"text-align: start;\">5.4 第四阶段 - 优化和测试</h3><ol><li style=\"text-align: start;\">性能优化（缓存、索引等）</li><li style=\"text-align: start;\">UI/UX优化</li><li style=\"text-align: start;\">安全性测试与加固</li><li style=\"text-align: start;\">全面功能测试与bug修复</li></ol><h2 style=\"text-align: start;\">6. 项目部署</h2><h3 style=\"text-align: start;\">6.1 开发环境</h3><ul><li style=\"text-align: start;\">JDK 17+</li><li style=\"text-align: start;\">Node.js 18+</li><li style=\"text-align: start;\">MySQL 8.0+</li><li style=\"text-align: start;\">Maven 3.8+</li></ul><h3 style=\"text-align: start;\">6.2 生产环境</h3><ul><li style=\"text-align: start;\">服务器：Linux (Ubuntu/CentOS)</li><li style=\"text-align: start;\">Web服务器：Nginx</li><li style=\"text-align: start;\">应用服务器：SpringBoot内置Tomcat</li><li style=\"text-align: start;\">数据库：MySQL 8.0+</li><li style=\"text-align: start;\">缓存：Redis (可选)</li></ul><h3 style=\"text-align: start;\">6.3 部署步骤</h3><ol><li style=\"text-align: start;\">前端项目打包：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>npm run build</code></span></li><li style=\"text-align: start;\">后端项目打包：<span style=\"color: rgb(0, 0, 0); background-color: rgb(240, 240, 240);\"><code>mvn clean package</code></span></li><li style=\"text-align: start;\">配置Nginx反向代理</li><li style=\"text-align: start;\">配置MySQL数据库</li><li style=\"text-align: start;\">启动后端服务</li><li style=\"text-align: start;\">配置域名和HTTPS (可选)</li></ol><h2 style=\"text-align: start;\">7. 项目维护与更新计划</h2><h3 style=\"text-align: start;\">7.1 定期维护</h3><ul><li style=\"text-align: start;\">安全漏洞修复</li><li style=\"text-align: start;\">依赖库更新</li><li style=\"text-align: start;\">性能监控与优化</li></ul><h3 style=\"text-align: start;\">7.2 功能更新计划</h3><ul><li style=\"text-align: start;\">增加社交媒体分享功能</li><li style=\"text-align: start;\">集成第三方登录</li><li style=\"text-align: start;\">开发移动端适配</li><li style=\"text-align: start;\">增加数据统计和分析功能</li><li style=\"text-align: start;\">集成富文本编辑器选项</li></ul><p><br></p>', '本项目是一个基于SpringBoot+Vue3的个人博客系统，采用前后端分离架构，实现博客内容的发布、管理、展示等功能', '/img/1.jpg', 1, 1, 1145, 1, 1, 1, '2026-05-20 11:45:14', '2026-05-20 11:45:14', 1, 0);
